import './NewDropdownMenu.scss';

import type { PopupsContextData } from ':helpers';
import { PopupsContext } from ':helpers';
import type { ReferenceElement } from '@floating-ui/react';
import {
	autoUpdate,
	FloatingOverlay,
	FloatingPortal,
	flip,
	offset,
	shift,
	size,
	useDismiss,
	useFloating,
	useInteractions,
} from '@floating-ui/react';
import React, { createContext, useContext, useEffect, useLayoutEffect, useState } from 'react';

import type { NewDropdownMenuProps } from './NewDropdownMenu.types';

const MENU_DEFAULT_OFFSET = 8;

export const DropdownContext = createContext<{
	applicationRootElementID?: string;
	dropdownElementID?: string;
	rootElement?: HTMLElement;
}>({});

export const NewDropdownMenu: React.FC<NewDropdownMenuProps & { children?: React.ReactNode }> = ({
	verticalOffset = MENU_DEFAULT_OFFSET,
	horizontalOffset = 0,
	align = 'bottom-start',
	targetElement,
	className,
	applicationRootElementID: applicationRootElementIDProps,
	dropdownElementID: dropdownElementIDProps,
	children,
	onOutsideClick,
	onBlur,
	scrollable = true,
	minHeight,
	dataTestId = 'DropdownMenu',
	isOpen,
	handleSetOpen,
	overlayScroll = true,
	widthMode = 'widthParent',
	onOpen,
	onClose,
	shouldRenderOverlay = false,
	overlayClassName,
	...rest
}) => {
	const {
		applicationRootElementID: applicationRootElementIDContext,
		dropdownElementID: dropdownElementIDContext,
		rootElement: rootElementDDContext,
	} = useContext(DropdownContext);

	const { applicationElementID, rootElement: rootElementContext } = useContext<PopupsContextData>(PopupsContext);

	const rootElementID =
		applicationRootElementIDProps || applicationRootElementIDContext || applicationElementID || 'root';
	let floatingPortalRootId = rootElementID;
	const element = rootElementDDContext || rootElementContext;
	const getRootElement = () => {
		const mountElement = element || document.getElementById(rootElementID) || document.body;
		if (mountElement instanceof ShadowRoot) {
			floatingPortalRootId = 'floating-ui-root';
			const floatingPortalRoot = mountElement.getElementById(floatingPortalRootId);
			if (!floatingPortalRoot) {
				const floatingContainer = document.createElement('div');
				floatingContainer.id = floatingPortalRootId;
				mountElement.append(floatingContainer);
				return floatingContainer;
			}
			const childrenArray = [...mountElement.children];
			const lastChild = childrenArray.at(-1);

			if (lastChild !== floatingPortalRoot) {
				floatingPortalRoot.remove();
				mountElement.append(floatingPortalRoot);
			}
			return floatingPortalRoot;
		}
		return mountElement as HTMLElement;
	};

	const [rootElement, setRootElement] = useState<HTMLElement>(getRootElement());

	useEffect(() => {
		setRootElement(getRootElement());
	}, [rootElementID, element]);

	const customSizeMiddleware = () =>
		size({
			apply: ({ rects, elements, availableHeight }) => {
				if (widthMode === 'widthParent' && rects && elements && availableHeight !== undefined) {
					Object.assign(elements.floating.style, {
						maxHeight: `${availableHeight}px`,
						width: `${rects.reference.width}px`,
					});
				}
				if (elements && availableHeight !== undefined) {
					Object.assign(elements.floating.style, {
						maxHeight: `${availableHeight}px`,
					});
				}
			},
		});

	const autoUpdateHook = (referenceEl: ReferenceElement, floatingEl: HTMLElement, update: () => void): (() => void) =>
		autoUpdate(referenceEl, floatingEl, update, { ancestorScroll: scrollable });

	const handleOpenChange = (nextOpen: boolean) => {
		if (nextOpen) {
			onOpen?.();
		} else {
			onClose?.();
		}
		handleSetOpen?.(nextOpen);
	};

	const { refs, floatingStyles, strategy, context, update } = useFloating({
		elements: { reference: targetElement.current },
		placement: align,
		middleware: [
			flip(),
			shift(),
			customSizeMiddleware(),
			offset({ mainAxis: verticalOffset, crossAxis: horizontalOffset }),
		],
		open: isOpen,
		onOpenChange: handleOpenChange,
		whileElementsMounted: autoUpdateHook,
	});

	const handleOutsideClick = (event: MouseEvent): boolean => {
		if (targetElement.current && targetElement.current.contains(event.target as Node)) {
			return false;
		}
		onOutsideClick?.(event);
		return true;
	};

	const dismiss = useDismiss(context, {
		outsidePress: handleOutsideClick,
	});

	const { getReferenceProps, getFloatingProps } = useInteractions([dismiss]);

	useLayoutEffect(() => {
		if (targetElement?.current) {
			refs.setReference(targetElement.current);
		}
	}, [refs, targetElement]);

	useLayoutEffect(() => {
		if (isOpen && targetElement?.current) {
			update();
		}
	}, [isOpen, targetElement, update]);

	if (!targetElement?.current) {
		return <></>;
	}

	return (
		<FloatingPortal root={rootElement}>
			{shouldRenderOverlay ? (
				<FloatingOverlay className={overlayClassName} lockScroll={overlayScroll}>
					<div
						style={{
							...floatingStyles,
							minWidth: '112px',
							minHeight,
						}}
						tabIndex={-1}
						ref={refs.setFloating}
						className={className}
						contentEditable={false}
						data-testid={dataTestId}
						onBlur={onBlur}
						{...rest}
						{...getFloatingProps()}
					>
						{children}
					</div>
				</FloatingOverlay>
			) : (
				<div
					style={{
						...floatingStyles,
						minWidth: '112px',
						minHeight,
					}}
					tabIndex={-1}
					ref={refs.setFloating}
					className={className}
					contentEditable={false}
					data-testid={dataTestId}
					onBlur={onBlur}
					{...rest}
					{...getFloatingProps()}
				>
					{children}
				</div>
			)}
		</FloatingPortal>
	);
};
